class Solution:
    def singleNumber(self, nums):
        result = 0
        for i in range(32):
            total = 0
            for v in nums:
                total += (v >> i) & 1
            bit = total % 3
            if bit:
                if i == 31:
                    result -= (1 << 31)
                else:
                    result |= (1 << i)
        return result

