var singleNumber = function(nums) {
    let result = 0;
    for (let i = 0; i < 32; i++) {
        let total = 0;
        for (const v of nums) {
            total += (v >> i) & 1;
        }
        const bit = total % 3;
        if (bit) {
            if (i === 31) {
                result -= Math.pow(2, 31);
            } else {
                result += (1 << i);
            }
        }
    }
    return result;
};
